#include <stdio.h>
#include <string.h>
int main() {
    int n;
    scanf("%d", &n);
    while (n--) {
        char s[101];
        scanf("%s", s);
        int len = strlen(s);
        int count = 0;
        for (int i = 0; i < len; i++) {
            if (s[i] == '_') {
                if (i > 0 && s[i - 1] != '_') count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

