code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        while (n-- > 0) {
            String s = scanner.next();
            int len = s.length();
            int count = 0;
            for (int i = 0; i < len; i++) {
                if (s.charAt(i) == '_') {
                    if (i > 0 && s.charAt(i - 1) != '_') count++;
                }
            }
            System.out.println(count);
        }
    }
}

