    if (i == 0) {
        n = parseInt(line);
        i++;
    } else {
        let s = line;
        let count = 0;
        for (let j = 0; j < s.length; j++) {
            if (s[j] == '_') {
                if (j > 0 && s[j - 1] != '_') count++;
            }
        }
        console.log(count);
        i++;
        if (i > n) {
            readline.close();
        }
    }
});

